    async checkFileSystem() {
        const issues = [];
        const checks = [
            { path: '.', name: 'Project Root' },
            { path: 'node_modules', name: 'Dependencies' },
            { path: 'services', name: 'Services' },
            { path: 'templates', name: 'Templates' }
        ];

        for (const { path: checkPath, name } of checks) {
            if (!fs.existsSync(checkPath)) {
                issues.push({
                    type: 'missing_directory',
                    path: checkPath,
                    severity: 'high',
                    fix: `create_directory:${checkPath}`
                });
            }
        }

        return { status: issues.length === 0 ? 'healthy' : 'needs_fixes', issues };
    }

    async analyzeDependencies() {
        const issues = [];
        
        try {
            const packageJson = JSON.parse(fs.readFileSync('package.json', 'utf8'));
            const dependencies = { ...packageJson.dependencies, ...packageJson.devDependencies };
            
            // Check for missing dependencies
            for (const [dep, version] of Object.entries(dependencies)) {
                const depPath = path.join('node_modules', dep);
                if (!fs.existsSync(depPath)) {
                    issues.push({
                        type: 'missing_dependency',
                        dependency: dep,
                        version,
                        severity: 'high',
                        fix: `install_dependency:${dep}@${version}`
                    });
                }
            }
            
        } catch (error) {
            issues.push({
                type: 'package_json_error',
                error: error.message,
                severity: 'high',
                fix: 'regenerate_package_json'
            });
        }

        return { status: issues.length === 0 ? 'healthy' : 'needs_fixes', issues };
    }

    async validateConfigurations() {
        const issues = [];
        const configFiles = [
            'gcp-config.json',
            'API_CONFIG_TEMPLATE.env',
            '.env'
        ];

        for (const configFile of configFiles) {
            if (!fs.existsSync(configFile)) {
                issues.push({
                    type: 'missing_config',
                    file: configFile,
                    severity: 'medium',
                    fix: `create_config_template:${configFile}`
                });
            }
        }

        return { status: issues.length === 0 ? 'healthy' : 'needs_fixes', issues };
    }

    async checkEnvironment() {
        const issues = [];
        
        try {
            // Check Node.js version
            const nodeVersion = process.version;
            if (!nodeVersion.startsWith('v18') && !nodeVersion.startsWith('v20')) {
                issues.push({
                    type: 'node_version_warning',
                    current: nodeVersion,
                    recommended: 'v18+',
                    severity: 'medium',
                    fix: 'upgrade_nodejs'
                });
            }
            
            // Check available memory
            const memoryUsage = process.memoryUsage();
            if (memoryUsage.heapUsed > 500 * 1024 * 1024) { // 500MB
                issues.push({
                    type: 'high_memory_usage',
                    usage: memoryUsage.heapUsed,
                    severity: 'low',
                    fix: 'optimize_memory'
                });
            }
            
        } catch (error) {
            issues.push({
                type: 'environment_check_error',
                error: error.message,
                severity: 'medium',
                fix: 'manual_environment_check'
            });
        }

        return { status: issues.length === 0 ? 'healthy' : 'needs_fixes', issues };
    }

